-- 1. Painters & Decorators × Web Design
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'painters-and-decorators',
  'web-design',
  'A painter and decorator''s website must do one thing exceptionally well: prove that your finish quality is worth the price. Homeowners choosing between decorators scrutinise the details — clean cut-in lines, smooth wall finishes, crisp masking, and colour choices that transform rooms. Your website needs to showcase this craftsmanship through high-quality room transformation galleries, clearly defined service offerings from single-room refreshes to full property renovations, and a frictionless path from browsing to booking a quote visit. Most decorator websites either have no portfolio at all or display a handful of poorly lit phone photos that fail to capture the finish quality that differentiates skilled work from amateur results. Generic template sites with stock images of paint rollers actively damage credibility. We build bespoke websites for painters and decorators that present your completed work with the visual quality it deserves and convert that impression into booked quote appointments.',
  'Homeowners compare multiple decorators before choosing, and your website is where the shortlist is decided. A professionally presented portfolio of room transformations, clear service descriptions covering interior decorating, exterior painting, wallpapering, and specialist finishes, and straightforward quote request functionality give potential customers the confidence to choose your business over cheaper competitors. Without this, price becomes the only differentiator.',
  'We photograph or professionally present your completed room transformations with consistent lighting and angles that highlight finish quality. Service pages cover each offering with detail that demonstrates expertise — from heritage colour consultations to exterior masonry coating — and every page drives visitors toward a quote request with room details.',
  '[{"title": "No portfolio showcasing the quality of finished work", "description": "Most painters and decorators have no online gallery of completed projects, or display a few phone photos that fail to show the smooth finishes, clean lines, and colour transformations that distinguish professional work from DIY results. Without visual proof of quality, customers default to choosing the cheapest quote."}, {"title": "Website does not differentiate from cheaper competitors", "description": "Template websites for decorators look identical — the same stock images of paint tins, the same generic service lists. When every decorator''s website says the same thing, homeowners cannot distinguish the skilled craftsperson charging a fair rate from the cheapest operator, and they default to price comparison."}, {"title": "No service breakdown explaining specialist capabilities", "description": "Decorators who offer specialist services — period property restoration, wallpapering, exterior coatings, spray finishing — often fail to communicate these on their website. Without dedicated service pages, customers with specific requirements cannot find evidence that you offer what they need."}]',
  '[{"title": "Room transformation galleries with before-and-after presentation", "description": "We build portfolio galleries showcasing completed work with before-and-after sliders for each room or project. Professional presentation highlights the finish quality — smooth walls, crisp edges, colour accuracy — that distinguishes your work and justifies your pricing against cheaper alternatives."}, {"title": "Detailed service pages for every specialism", "description": "Dedicated pages for interior decorating, exterior painting, wallpapering, spray finishing, heritage property work, and commercial decorating each demonstrate specific expertise. Detailed descriptions of process, materials, and preparation standards educate customers and pre-qualify enquiries for the services you actually want to deliver."}, {"title": "Quote request forms with room and project details", "description": "Structured quote request forms collect room dimensions, surface conditions, colour preferences, and project timelines before you visit. This pre-qualifying information helps you prepare accurate estimates and prioritise enquiries from customers whose projects match your preferred scope and value."}]',
  '[{"question": "How do you make painting work look impressive on a website?", "answer": "Consistent photography with good lighting is key. We provide guidance on capturing room transformations — specific angles for before-and-after shots, lighting tips, and staging suggestions. We then present these images in before-and-after slider formats that let visitors appreciate the dramatic difference professional decorating makes."}, {"question": "Can a website help me attract higher-value decorating jobs?", "answer": "Absolutely. By showcasing specialist work — period property restoration, high-end wallpapering, heritage colour schemes, commercial projects — your website attracts customers seeking specific expertise rather than the cheapest quote. Detailed service pages and premium project galleries position your business for the work you want to win."}, {"question": "Do I need separate pages for each decorating service?", "answer": "Yes. Dedicated pages for interior painting, exterior painting, wallpapering, specialist finishes, and commercial work each target different search terms and demonstrate specific expertise. This also helps customers with particular requirements find confirmation that you offer exactly what they need."}, {"question": "Will the website work on mobile for customers at home?", "answer": "Yes. Many homeowners browse decorator websites while standing in the room they want decorated. Every site we build is fully responsive with fast-loading image galleries, touch-friendly navigation, and tap-to-call functionality for instant contact while the motivation is fresh."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 2. Painters & Decorators × SEO
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'painters-and-decorators',
  'seo',
  'When a homeowner searches "painter and decorator near me" or "wallpapering service Kent," the decorators appearing in the top Google results win the majority of enquiries. Painting and decorating is a highly competitive local search market — every town has multiple operators, and the Google Map Pack positions are fiercely contested. Yet most decorators rely entirely on word of mouth and Checkatrade listings, surrendering organic search visibility to the competitors and directory platforms that invest in SEO. A painting and decorating SEO strategy must target both broad service terms and specific high-value searches: exterior house painting, period property restoration, commercial decorating contracts, and wallpaper hanging. Each requires dedicated content demonstrating expertise that generic "painter and decorator" pages cannot match. We build SEO campaigns for painters and decorators that capture local search traffic across every service you offer and convert that visibility into quote requests.',
  'Word of mouth referrals are unpredictable and unscalable. When work slows between referrals, you need a steady stream of customers actively searching for decorating services in your area. SEO provides that pipeline by ensuring your business appears when homeowners and property managers search for the exact services you offer. Without it, those customers go to whichever competitor Google shows them first.',
  'We target specific decorating services — not just generic "painter decorator" terms, but high-intent searches like "wallpaper hanging [town]," "exterior house painter," and "commercial decorator Kent." Each service gets a dedicated optimised page. Google Business Profile optimisation features completed project photos categorised by service type.',
  '[{"title": "Invisible for specific decorating service searches", "description": "Customers searching for specialist services — wallpapering, exterior painting, spray finishing, heritage property work — cannot find your business because your website has no dedicated, optimised content for these terms. Generic ''painter and decorator'' pages do not rank for specific service queries that indicate strong buying intent."}, {"title": "Checkatrade and MyBuilder outranking your own website", "description": "Trade directory platforms invest heavily in SEO for decorating keywords in every town. Without your own search strategy, your business is invisible in organic results, forcing you to pay commission-based lead fees for enquiries that should come directly from your own website."}, {"title": "Google Map Pack positions held by competitors with more reviews", "description": "The Map Pack results for painting and decorating searches — the positions that generate the most phone calls — are dominated by competitors who actively collect Google reviews. Without a systematic review strategy, your business remains below the fold regardless of your workmanship quality."}]',
  '[{"title": "Service-specific landing pages targeting high-intent searches", "description": "We create dedicated, SEO-optimised pages for each service: interior decorating, exterior painting, wallpapering, spray finishing, commercial decorating, and specialist finishes. Each page targets specific search terms, demonstrates expertise through detailed process descriptions, and converts visitors into quote requests."}, {"title": "Google Business Profile optimisation with project photography", "description": "Your Google Business Profile is fully optimised with service-specific categories, completed project photos organised by type, and a structured review collection programme. This drives visibility in the Map Pack — the most prominent position for local decorating searches — and generates direct phone calls and quote requests."}, {"title": "Local service-area pages for towns in your coverage zone", "description": "Dedicated pages targeting each town and area you serve — ''painter and decorator in [town]'' — capture location-specific searches that directory platforms handle generically. These pages include local references, area-specific content, and project examples from nearby customers."}]',
  '[{"question": "How competitive is SEO for painters and decorators?", "answer": "Local decorating searches are moderately competitive. National directories hold strong positions, but dedicated local SEO targeting specific services and locations can achieve first-page rankings within three to six months. Service-specific terms like ''wallpaper hanging'' and ''exterior painting'' often have less competition than generic painter searches."}, {"question": "Which decorating searches should I target first?", "answer": "We prioritise your highest-margin services in your core service area. For most decorators, this means interior decorating and exterior painting plus your primary towns. Specialist services like wallpapering and spray finishing typically face less competition and can rank faster, building momentum while broader terms gain traction."}, {"question": "How many Google reviews do I need to rank in the Map Pack?", "answer": "The number varies by location, but consistently gaining reviews is more important than a specific count. We implement automated review request workflows that build your review count steadily after each completed job. Most decorators see meaningful Map Pack improvements after accumulating fifteen to twenty recent, detailed reviews."}, {"question": "Can SEO reduce my dependency on Checkatrade?", "answer": "Yes. As your organic visibility grows, direct enquiries from Google increase, reducing your reliance on paid directory leads. Most decorating clients see a significant shift from directory-sourced to direct enquiries within six months of starting SEO, progressively improving their profit margin per job."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
