  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 3. Painters & Decorators × Lead Capture
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'painters-and-decorators',
  'lead-capture',
  'Most painting and decorating websites lose visitors who are not ready to request a quote immediately. A homeowner might be researching decorators weeks before their project starts, comparing portfolios and getting a sense of pricing without committing to a quote visit yet. Without lead capture tools that offer value at this early research stage, these prospects leave your site and you have no way to follow up when they are ready to proceed. Effective lead capture for decorators means providing tools that visitors genuinely want to engage with: a room painting cost estimator, a colour scheme inspiration guide, or a property redecoration checklist that helps them plan their project. Each tool captures contact details and project information in exchange for genuine value, transforming anonymous browsers into named prospects you can nurture through to booking. We build lead capture systems for painters and decorators that capture early-stage researchers and convert them into booked quote appointments.',
  'Decorating projects typically involve a consideration period — homeowners research colours, compare decorators, plan budgets, and choose timing before committing. If your website only captures visitors who are ready to request a quote today, you miss everyone in the research phase. Lead capture tools engage these early-stage prospects, collect their details and project requirements, and keep your business front of mind through the decision period until they are ready to book.',
  'We build decorator-specific lead capture tools: room cost estimators asking about room sizes, surface conditions, and finish preferences; colour scheme guides and room inspiration lookbooks; and property redecoration checklists that help homeowners plan multi-room projects. Each captures details and feeds into a follow-up sequence.',
  '[{"title": "Website visitors researching but not requesting quotes", "description": "Homeowners browsing decorator websites during the research phase — comparing portfolios, assessing professionalism, getting a feel for pricing — rarely request quotes on their first visit. Without capturing their details, you lose every early-stage researcher to whichever competitor they remember when they are finally ready to proceed."}, {"title": "No way to stay in contact through the decision period", "description": "The gap between initial research and project commitment can stretch to weeks or months for decorating work. Without email capture and a follow-up nurture sequence, you cannot maintain visibility during this period and rely entirely on the customer remembering your business when they are ready."}, {"title": "Quote requests lacking useful project information", "description": "Generic contact forms produce vague enquiries — ''how much to paint my lounge?'' — with no information about room size, surface condition, access requirements, or timeline. Responding to these requires lengthy back-and-forth before you can provide any meaningful estimate."}]',
  '[{"title": "Room painting cost estimator", "description": "An interactive calculator asks about room dimensions, number of walls and ceilings, surface condition, and desired finish quality. In exchange for their email, homeowners receive an approximate cost range. You receive their contact details alongside detailed project specifications — room sizes, conditions, and preferences — ready for follow-up."}, {"title": "Colour scheme inspiration guide", "description": "A downloadable guide featuring popular colour schemes for different room types — calming bedrooms, statement living rooms, practical kitchens — captures email addresses from homeowners in the planning phase. The guide subtly demonstrates your colour consultation expertise while keeping your business front of mind during the research period."}, {"title": "Property redecoration planner with email nurture", "description": "A planning tool that helps homeowners scope multi-room projects — which rooms need attention, priority order, budget allocation — captures comprehensive project details. An automated email sequence then delivers helpful preparation tips, colour advice, and portfolio examples over the following weeks."}]',
  '[{"question": "What lead magnets work for painters and decorators?", "answer": "Room cost estimators, colour scheme inspiration guides, property redecoration planners, and seasonal decorating tips all perform well for decorating businesses. The most effective approach depends on your target customer — premium residential clients respond to colour consultation content while general decorating customers engage with cost estimators."}, {"question": "Will a cost estimator commit me to a price?", "answer": "No. The estimator provides approximate ranges based on typical room sizes and standard preparation requirements. Clear disclaimers explain that actual costs depend on a site assessment of surface conditions, access, and specific requirements. The purpose is to give customers useful guidance while capturing their project details."}, {"question": "How many extra leads should I expect?", "answer": "Decorators typically see a three to four times increase in captured leads after implementing estimator and guide-based lead capture. For a website receiving three hundred monthly visitors, this translates to approximately ten to fifteen additional contactable prospects per month, each with detailed project requirements."}, {"question": "Can leads be sent directly to my phone?", "answer": "Yes. Every captured lead generates an instant notification via email, SMS, or both. You receive the prospect''s contact details, room specifications, timeline, and any other information collected by the form. Leads can also feed into CRM systems, project management tools, or Google Sheets."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
