  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 4. Painters & Decorators × Business Automation
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'painters-and-decorators',
  'business-automation',
  'The rhythm of a painting and decorating business creates predictable admin bottlenecks: quote requests pile up while you are on-site, sent quotes languish without follow-up because you are busy on the next job, completed projects generate no review requests because you have already moved on, and past customers never hear from you again even when their property is due for repainting. Business automation for decorators eliminates these bottlenecks with workflows that trigger at each stage of the customer journey. A new enquiry receives an instant acknowledgement with your portfolio link. A sent quote triggers a follow-up sequence at forty-eight hours, one week, and two weeks. A completed job generates a review request at the point of peak satisfaction — when the rooms are freshly painted and the dust sheets are packed away. And past customers receive timely reminders when their exterior paintwork or high-traffic rooms are likely due for refreshing. We build automation systems for painters and decorators that ensure no opportunity slips through the gaps in a busy work schedule.',
  'Decorators lose significant revenue to forgotten follow-ups and missed opportunities. A quote sent on Friday evening and never chased by Wednesday has likely gone to a competitor. A beautifully finished room generates no Google review because the request was never made. A customer whose hallway you painted three years ago hires someone else for the bedrooms because they forgot your name. Automation prevents every one of these revenue leaks with zero ongoing effort.',
  'We automate the decorator''s customer journey: instant enquiry acknowledgements with portfolio links, timed quote follow-up sequences, booking confirmation with preparation instructions for the homeowner, post-completion review requests, and periodic repainting reminders based on surface type and paint lifespan.',
  '[{"title": "Quotes sent but never followed up while busy on-site", "description": "Decorators spend full days on-site and rarely have time to follow up on outstanding quotes in the evenings. Without systematic follow-up, quotes that could have converted with a simple reminder go cold, and customers who were genuinely considering your proposal choose the decorator who chased first."}, {"title": "Completed jobs generating no reviews or referrals", "description": "The moment a decorating job is finished — when the customer is delighted with freshly painted rooms — is the optimal time to request a review. But decorators move straight to the next job and the request is never made, missing the reviews that drive search visibility and the referrals that generate word-of-mouth work."}, {"title": "Past customers lost with no repainting reminders", "description": "Exterior paintwork typically needs refreshing every five to seven years, while high-traffic interior rooms may need attention every three to four years. Without automated reminders, past customers either forget about you or assume you are too busy, and search for another decorator when the time comes."}]',
  '[{"title": "Automated quote follow-up sequences", "description": "Every sent quote triggers a timed follow-up sequence: a friendly check-in after forty-eight hours, a reminder after one week with a portfolio link reinforcing your quality, and a final message after two weeks. Each email is personalised with the customer''s project details. Quote conversion rates typically increase by thirty to forty percent."}, {"title": "Post-completion review and referral requests", "description": "Two days after project completion — when satisfaction peaks with freshly decorated rooms — an automated message requests a Google review with a direct link. A follow-up thanks them for the review and includes a referral prompt with a shareable link. This systematic approach builds your review count consistently."}, {"title": "Repainting reminder campaigns based on project type", "description": "Automated reminders contact past customers at appropriate intervals: exterior painting customers after five years, high-traffic room customers after three years, and full property redecoration customers annually with seasonal maintenance tips. These reminders generate repeat business from your existing customer base with no manual effort."}]',
  '[{"question": "What can be automated for a painting and decorating business?", "answer": "The highest-impact automations are enquiry acknowledgements, quote follow-ups, booking confirmations with preparation instructions, post-completion review requests, repainting reminders to past customers, and seasonal marketing campaigns. We also automate appointment reminders and weather delay notifications for exterior work."}, {"question": "How do customer preparation instructions work?", "answer": "When a job is booked, an automated message is sent to the customer with preparation guidelines for their specific project: moving furniture away from walls, clearing shelves, covering or removing valuables, and providing access requirements. This reduces delays on your first day on-site and demonstrates professional communication."}, {"question": "Will automated messages feel genuine to my customers?", "answer": "Every message is personalised with the customer''s name, project details, and your brand voice. The tone is warm and professional, not robotic. Customers experience faster, more reliable communication — and most do not realise the follow-ups are automated because they feel like natural, well-timed messages."}, {"question": "How do repainting reminders know when to trigger?", "answer": "We set reminder timelines based on the project type and paint specifications used. Exterior masonry coating might trigger a check-in after five to six years, while a high-traffic hallway might prompt a reminder after three years. You control the intervals for each project type based on your professional knowledge of paint lifespan."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
