-- 6. Painters & Decorators × Social Media Setup
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'painters-and-decorators',
  'social-media-setup',
  'Painting and decorating work is perfectly suited to social media — room transformations produce satisfying before-and-after content, colour consultations showcase expertise, and behind-the-scenes preparation work demonstrates the craft that justifies professional pricing. Yet most decorators either have no social media presence or post occasional, poorly lit progress photos with no strategy behind them. Setting up social media effectively for a decorating business means establishing branded profiles, creating content categories that showcase different aspects of your work, and building a capture system that makes documenting jobs effortless. A well-curated Instagram feed of room transformations becomes a visual portfolio that customers browse before making contact — often carrying more influence than your website because it shows recent, consistent output. We set up social media for painters and decorators with branded templates, systematic photo capture guidelines, and content plans designed for tradespeople who spend their days with brushes, not phones.',
  'Homeowners increasingly check social media before hiring a decorator, using Instagram as a visual portfolio to assess finish quality and style. A consistent social presence with recent project photography builds confidence in your active trading status and demonstrates the standard of work customers can expect. Without it, you are invisible to the growing number of people who discover tradespeople through social platforms and word-of-mouth sharing.',
  'We set up decorator social accounts with room transformation templates — consistent framing for before-and-after reveals — colour showcase posts, and behind-the-scenes preparation content. Photo capture guidelines ensure your team documents each room at key stages with minimal disruption to the work schedule.',
  '[{"title": "Stunning room transformations never shared publicly", "description": "Decorators create dramatic visual improvements every week — dated magnolia transformed into statement feature walls, tired exteriors restored to crisp finishes — but these results are never documented for social media. This free marketing content goes entirely to waste while competitors with inferior skills but better social habits attract more work."}, {"title": "Inconsistent posting that damages rather than builds credibility", "description": "Decorators who post sporadically — a flurry of photos during one job followed by months of silence — create a social presence that looks unreliable. Potential customers checking your profile see long gaps and assume you are either too busy to bother or struggling for consistent work."}, {"title": "Phone photos failing to capture finish quality", "description": "Quick phone photos taken in poor lighting with cluttered backgrounds do not capture the smooth finishes, clean lines, and colour accuracy that define quality decorating. Without guidance on capturing work effectively, even excellent craftsmanship looks mediocre on social media."}]',
  '[{"title": "Branded room transformation templates", "description": "We create consistent before-and-after post templates that frame your room transformations with professional presentation. Branded borders, your logo placement, and consistent formatting create a cohesive grid that looks polished and professional — a visual portfolio that sells your work at a glance."}, {"title": "Photo capture system for on-site documentation", "description": "Simple guidelines for capturing each room at three stages: before (showing the existing condition), during preparation (demonstrating the thoroughness of your prep work), and the final reveal. Specific angles, lighting tips, and framing guidance ensure consistent, high-quality content with minimal disruption to your work."}, {"title": "Content calendar with category rotation", "description": "A structured posting plan rotates between room reveals, colour consultation showcases, preparation process content, and customer testimonial highlights. This variety demonstrates different aspects of your expertise — craftsmanship, colour knowledge, preparation standards, and customer satisfaction — maintaining engagement and attracting diverse project enquiries."}]',
  '[{"question": "Which social platform is best for painters and decorators?", "answer": "Instagram is the highest-performing platform for decorators because of its visual focus — room transformation posts and reels generate strong engagement and act as a living portfolio. Facebook is important for local community reach and sharing. We set up both with consistent branding and distinct content strategies."}, {"question": "How should I photograph my decorating work for social media?", "answer": "We provide a simple three-stage capture system: photograph the room before starting, during preparation showing your thoroughness, and the final result. Key tips include using natural light where possible, clearing clutter from the frame, and shooting from a consistent angle in the doorway or corner for each stage."}, {"question": "How often should a decorator post on social media?", "answer": "Three to four posts per week works well for decorators: two room transformation reveals, one behind-the-scenes or preparation post, and one colour tip or customer review highlight. Our template system makes creating these posts a five to ten minute task rather than a time-consuming creative exercise."}, {"question": "Can social media actually generate decorating enquiries?", "answer": "Yes. Before-and-after room transformations are among the most shared and saved content types on social media. Satisfied customers share your posts with friends and neighbours, generating organic referrals. A consistent, professional social presence also builds the credibility that converts website visitors who check your social profiles before making contact."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
