-- 7. Painters & Decorators × Digital Marketing
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'painters-and-decorators',
  'digital-marketing',
  'Digital marketing for painters and decorators must account for the cyclical nature of decorating demand and the wide variation in project values. Spring and summer see surges in exterior painting requests, while interior redecoration peaks in autumn and the new year period as homeowners refresh their homes. A decorator targeting full property renovations needs entirely different marketing messaging than one focused on single-room refreshes. An effective decorating marketing strategy aligns campaigns to seasonal demand patterns, segments messaging by project type and value, and uses real room transformation photography to stop social media scrollers in their tracks. Most decorators either run no paid marketing at all or throw money at boosted Facebook posts with no targeting strategy, generating likes rather than leads. We build and manage digital marketing campaigns for painters and decorators that deliver a measurable pipeline of quote requests matched to the project types and values you actually want to win.',
  'Word of mouth delivers inconsistent work flow — feast during recommendation waves and famine between them. Digital marketing provides a controllable, measurable source of new enquiries that fills gaps between referrals and scales with your ambitions. Targeted campaigns put your work in front of homeowners actively planning decorating projects, at the moment their intent is highest, generating quote requests from customers already motivated to proceed.',
  'We align decorating campaigns to seasonal demand: exterior painting ads from spring through summer, interior refresh campaigns in autumn, and full property redecoration targeting in January. Ad creative features your actual before-and-after room transformations, and audience targeting focuses on homeowners within your service radius.',
  '[{"title": "Marketing budget wasted on untargeted boosted posts", "description": "Decorators who boost Facebook posts without audience targeting generate engagement from people with no intention of hiring a decorator. Likes and comments feel encouraging but deliver no quote requests, wasting marketing budget that could be driving genuine enquiries from homeowners in your service area."}, {"title": "No seasonal campaign strategy matching decorating demand", "description": "Running the same ads year-round ignores the seasonal rhythms of decorating demand. Exterior painting campaigns in November and interior refresh ads in July misalign your marketing with customer intent, reducing conversion rates and wasting spend on poorly timed messaging."}, {"title": "Generic ad creative failing to differentiate from competitors", "description": "Decorating ads featuring stock images of paint tins or generic ''professional painting services'' messaging look identical to every competitor. Without compelling before-and-after room transformations from your actual projects, your ads fail to demonstrate the quality difference that justifies your pricing."}]',
  '[{"title": "Seasonal campaign calendar matched to decorating demand", "description": "We plan and execute campaigns on a twelve-month calendar: exterior painting from March through August, interior refresh campaigns from September through November, and full property redecoration targeting in January and February. Budget allocation shifts monthly to align spend with the seasonal searches driving decorating decisions."}, {"title": "Before-and-after ad creative from your real projects", "description": "Social media ads featuring your actual room transformations dramatically outperform stock imagery. Before-and-after carousel ads showing dated rooms transformed into stunning spaces stop the scroll and demonstrate your quality in seconds — generating engagement and quote requests from genuinely interested homeowners."}, {"title": "Project-value segmented campaigns", "description": "We run separate campaigns targeting different project values: single-room refresh ads reaching price-conscious homeowners, full property redecoration campaigns targeting premium audiences, and commercial decorating ads reaching property managers and businesses. Each segment receives messaging and creative tailored to its specific priorities and budgets."}]',
  '[{"question": "How much should a painter and decorator spend on digital marketing?", "answer": "Most decorators see strong returns starting at two hundred to five hundred pounds per month, targeting their highest-margin services in core areas. Given that a typical decorating job generates hundreds to thousands in revenue, even modest marketing budgets deliver significant return when campaigns are properly targeted and seasonal."}, {"question": "Do before-and-after ads really work for decorators?", "answer": "Before-and-after room transformations are among the highest-performing ad formats on Facebook and Instagram. They demonstrate your quality instantly, generate shares and saves, and produce click-through and enquiry rates significantly above generic decorating ads. Real project photography consistently outperforms stock images."}, {"question": "Can digital marketing fill quieter periods between referrals?", "answer": "Yes. Targeted campaigns running during your historically quieter months generate enquiries from homeowners who would not have found you through word of mouth alone. Many decorating clients achieve consistent year-round workloads by combining steady referrals with strategic digital marketing during seasonal dips."}, {"question": "How do you track which marketing generates quote requests?", "answer": "Every campaign is tracked from ad impression through to quote request. We use dedicated landing pages, call tracking, and form attribution to identify exactly which ads, platforms, and audiences generated each enquiry. Monthly reports show cost per lead and return on marketing investment clearly."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 8. Painters & Decorators × Workwear & Print
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'painters-and-decorators',
  'workwear-print',
  'Painters and decorators work inside people''s homes — often for days at a time — and first impressions at the door directly affect customer confidence. A decorator arriving in branded workwear with a professionally designed van parked outside communicates reliability and professionalism before a single brush stroke. Conversely, unmarked clothing and an unbranded van can make homeowners uneasy about who they have invited into their home. Beyond the initial impression, your presence in a property generates neighbour curiosity — branded workwear and van livery visible from the street turn every job into passive advertising for the surrounding homes. Printed leave-behind materials — business cards, room repaint reminder cards, and neighbourhood introduction postcards — extend this marketing beyond the duration of the job. We provide painters and decorators with branded workwear designed for the realities of decorating work, professional van livery, and printed materials that maximise the marketing value of every project.',
  'Decorators spend days inside customers'' homes and are visible to neighbours from the street throughout every project. Branded workwear builds homeowner confidence at the front door and creates a professional impression for every passer-by. Van livery parked outside a property is seen by the entire street. Printed leave-behind materials convert that visibility into future enquiries. These physical brand touchpoints are disproportionately impactful for a trade that operates in public view on residential streets.',
  'We supply decorator-appropriate workwear — lightweight embroidered polos for interior work, branded overalls that maintain presentation during messy preparation stages, and softshell jackets for exterior work. Printed materials include post-completion cards with a room refresh reminder schedule and neighbour introduction postcards.',
  '[{"title": "Working inside customers'' homes without branded identification", "description": "Decorators spend extended periods inside private homes, and homeowners increasingly expect professional identification. Unbranded workers create unease, particularly when the homeowner is absent during the work. Branded workwear immediately identifies your team as the expected, professional business."}, {"title": "Paint-covered workwear undermining professional image", "description": "The nature of decorating means clothing gets covered in paint and filler quickly. Without durable, paint-appropriate workwear designed to maintain a professional appearance despite the messy realities of the job, your team''s presentation deteriorates throughout the day and across the week."}, {"title": "No marketing materials left for neighbours to find", "description": "A decorator working on a property for several days is noticed by every neighbour. Without a leave-behind card or postcard for adjacent homes, this extended visibility generates zero follow-up enquiries — a significant missed opportunity on every residential job."}]',
  '[{"title": "Decorator-specific branded workwear", "description": "We supply workwear designed for decorating conditions: lightweight embroidered polo shirts for interior work, branded painter''s overalls for preparation and messy stages, waterproof jackets for exterior projects, and branded caps. Materials are selected for durability and ease of cleaning, maintaining a professional appearance through the demands of daily decorating work."}, {"title": "Neighbour introduction postcards and completion cards", "description": "After completing a project, branded postcards are delivered to surrounding homes: ''We have just finished transforming a property on your street — here is what we do.'' Post-completion cards left with the customer include a room refresh reminder schedule and referral incentive, generating future bookings and word-of-mouth recommendations."}, {"title": "Van livery reflecting decorating craftsmanship", "description": "Clean, sophisticated van livery that mirrors the precision and quality of your decorating work. No clip-art paintbrushes — instead, a design that communicates professionalism and attention to detail. Your contact information is prominently displayed and legible from across the street where your van is parked during every job."}]',
  '[{"question": "What workwear suits painting and decorating work?", "answer": "We recommend embroidered polo shirts for clean-stage work and client interactions, branded overalls for preparation and painting stages, softshell jackets for exterior work, and branded caps. All items are chosen for washability, durability, and the ability to maintain a professional appearance through the messy realities of decorating."}, {"question": "How do neighbour postcards generate new work?", "answer": "When you complete a property transformation, branded postcards are delivered to twenty to thirty surrounding homes highlighting that professional decorating has just been completed on their street. Each card includes your portfolio link and contact details. Our decorating clients typically generate one to two new enquiries per postcard drop from curious neighbours."}, {"question": "Can workwear withstand daily paint and filler exposure?", "answer": "Yes. We select fabrics and print methods specifically for trades that encounter paint, filler, and dust. Embroidered logos resist peeling, chosen fabrics are easily washable, and we recommend rotating stock to maintain consistent presentation. We also offer disposable branded dust covers for heavy preparation work."}, {"question": "Do you supply branded dust sheets or site protection?", "answer": "We can source branded dust sheets and floor protectors featuring your logo. These create a professional impression during the job — customers notice when a decorator protects their home with branded materials rather than paint-spattered sheets. It is a small detail that reinforces the quality-conscious image your branding communicates."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 9. Painters & Decorators × AI Chatbots
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'painters-and-decorators',
  'ai-chatbots',
  'Decorators are on-site with brushes and rollers in hand from early morning until late afternoon, with zero opportunity to answer phone calls or respond to website enquiries. By the time the dust sheets are packed away and messages are checked, motivated prospects have already called two other decorators and booked a quote visit with whoever responded first. An AI chatbot built for painting and decorating businesses handles these enquiries in real time: asking about the rooms needing attention, the current condition of walls and woodwork, the type of finish desired, and the preferred timeline. It can share your portfolio to build confidence, explain your preparation process to set quality expectations, and book a quote visit directly into your calendar. For homeowners browsing decorator websites on a Sunday afternoon while staring at their tired lounge walls, an instant, helpful conversation converts impulse research into a booked appointment. We build AI chatbots for decorators that capture and qualify every enquiry while you focus on delivering flawless finishes.',
  'Decorating enquiries arrive throughout the day — homeowners searching during lunch breaks, evenings, and weekends when inspiration strikes. With your hands occupied on-site, these enquiries go unanswered for hours, by which time the prospect has moved on. An AI chatbot provides the instant response that captures the enquiry, qualifies the project, and books the quote visit — all while you are focused on the job in front of you.',
  'Our decorating chatbots ask the specific questions that qualify a decorating enquiry: which rooms need attention, wall and ceiling conditions, woodwork requirements, wallpaper removal needs, colour preferences, and access arrangements. This pre-qualification means every quote visit is informed, efficient, and focused on projects that match your capabilities.',
  '[{"title": "All-day on-site work preventing timely enquiry responses", "description": "Painters and decorators work with their hands for eight or more hours daily. Answering phones risks paint drips, interrupts focus, and irritates customers whose property you are working on. But leaving enquiries until evening means losing prospects to the decorator who picked up the phone."}, {"title": "Quote visits wasted on poorly qualified projects", "description": "Without pre-qualification, decorators drive to quote visits only to discover rooms in conditions far worse than described, customers expecting luxury finishes at budget prices, or projects far below their minimum value. Each wasted visit costs an hour or more of productive time."}, {"title": "Evening and weekend browsing going completely unengaged", "description": "Homeowners frequently research decorators during evenings and weekends — often while literally looking at the walls they want repainted. These highly motivated prospects receive no response until Monday morning, by which time the impulse has passed or a competitor has engaged them."}]',
  '[{"title": "Instant engagement capturing motivated homeowners", "description": "Your AI chatbot greets every website visitor within seconds, asks about their decorating requirements, and guides them through a friendly qualification conversation. Whether they visit during your busiest on-site hours or at ten o''clock on a Saturday evening, they receive an immediate, helpful response that keeps them engaged."}, {"title": "Detailed project pre-qualification before quote visits", "description": "The chatbot collects comprehensive project information: rooms requiring attention, wall and ceiling conditions, woodwork scope, wallpaper removal requirements, colour preferences, access arrangements, and timeline expectations. You arrive at every quote visit fully briefed, making consultations faster, more accurate, and more impressive."}, {"title": "Portfolio sharing and preparation process explanation", "description": "The chatbot shares relevant examples from your portfolio based on the project type discussed, building confidence in your quality before you visit. It explains your preparation standards — filling, sanding, priming — setting expectations that differentiate your thorough approach from cheaper competitors who cut corners."}]',
  '[{"question": "Can a chatbot handle the variety of decorating enquiries?", "answer": "Yes. We train the chatbot on your full service range — interior painting, exterior painting, wallpapering, spray finishing, specialist finishes, and commercial work. It asks relevant follow-up questions based on the service identified and adjusts its conversation to collect the specific information needed for each project type."}, {"question": "What happens if a customer asks something the chatbot cannot answer?", "answer": "The chatbot acknowledges the question, captures the customer''s contact details and specific query, and notifies you for a personal follow-up. It never guesses or provides inaccurate information. Complex technical questions are always escalated to you with full context of the conversation so far."}, {"question": "Can the chatbot help customers choose paint colours?", "answer": "The chatbot can discuss general colour approaches — warm versus cool tones, light versus dark rooms, feature wall considerations — and share examples from your portfolio showing similar colour schemes. For detailed colour consultation, it recommends booking a quote visit where you can assess the space in person and provide expert colour advice."}, {"question": "Will the chatbot book quote visits into my calendar?", "answer": "Yes. The chatbot integrates with your calendar and allows qualified prospects to select from your available consultation slots. You receive a notification with full project details — rooms, conditions, preferences, timeline — before each visit, ensuring you are prepared and every consultation is productive."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 10. Painters & Decorators × AI Content
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'painters-and-decorators',
  'ai-content',
  'Homeowners researching decorators search for practical advice before hiring: paint colour trends, preparation tips, how long interior paint lasts, whether wallpaper is making a comeback, and how to choose between matt and eggshell finishes. Decorators who publish this content capture these searches, demonstrate expertise, and build the trust that converts researchers into customers. But after a physical day of painting, the last thing a decorator has energy for is writing blog posts about colour theory or surface preparation techniques. AI-powered content creation solves this by generating authoritative decorating content calibrated to your services, expertise, and the search queries your potential customers actually use. Every piece is grounded in genuine trade knowledge — proper preparation sequences, paint and finish specifications, real decorating techniques — not generic home improvement filler. We set up AI content systems for painters and decorators that build your search visibility and demonstrate expertise without adding a single hour to your working week.',
  'Decorating customers research extensively before committing to projects that will transform their living spaces. Businesses publishing helpful content — colour guides, preparation explanations, finish comparisons, maintenance tips — capture search traffic from these research queries and position themselves as knowledgeable professionals. Without content, your website is invisible to the majority of decorating-related searches and fails to demonstrate the expertise that differentiates skilled decorators from cheap alternatives.',
  'Our AI content system produces decorating-specific material: colour trend analysis, paint type and finish comparisons, surface preparation guides, wallpaper selection advice, and maintenance tips. Content references actual products, techniques, and trade knowledge — proper sugar-soaping procedures, undercoat specifications, caulking methods — not superficial DIY tips.',
  '[{"title": "No time for content creation after physical workdays", "description": "Decorators finish work physically tired after full days of preparation, painting, and clearing up. Writing blog posts about colour trends or paint finish comparisons gets perpetually postponed, leaving the website static with thin service descriptions that fail to demonstrate the depth of your decorating knowledge."}, {"title": "Website content too thin to rank for decorating searches", "description": "Most decorator websites have brief service listings and a contact page. Without detailed content covering different services, paint and finish options, preparation processes, and colour advice, the site lacks the depth Google needs to rank it above competitors and directory platforms for relevant search terms."}, {"title": "Competitors publishing content building progressive advantage", "description": "Decorating businesses publishing regular guides, colour inspiration, and technique articles build search authority that compounds over time. Without producing comparable content, your site falls progressively further behind in rankings for the informational searches that drive decorating enquiries."}]',
  '[{"title": "Colour and finish guide content", "description": "AI generates detailed guides on topics homeowners search for: colour trends for the current year, choosing between paint finishes, wallpaper versus paint comparisons, feature wall colour selection, and exterior paint options. Each piece demonstrates your colour expertise and targets high-volume search terms that attract decorating prospects."}, {"title": "Preparation and process content demonstrating expertise", "description": "Detailed articles explaining proper surface preparation, why preparation matters more than the topcoat, how professional decorators handle different wall conditions, and what distinguishes a quality job from a quick paint-over. This content builds trust by demonstrating the thoroughness that justifies your pricing."}, {"title": "Seasonal decorating content calendar", "description": "A twelve-month content plan aligned to decorating search trends: spring refresh inspiration, summer exterior painting guides, autumn redecoration planning, and new year transformation motivation. AI generates each piece with genuine trade accuracy, maintaining a consistent publishing rhythm that builds search authority month by month."}]',
  '[{"question": "Will AI content sound like a real decorator wrote it?", "answer": "Yes. Our system is trained on genuine decorating trade knowledge — proper preparation techniques, paint specifications, application methods, and colour theory. Content references real products, actual processes, and professional terminology that demonstrates authentic trade expertise, not generic home improvement advice."}, {"question": "What topics does AI content cover for decorators?", "answer": "Colour guides and trends, paint finish comparisons, surface preparation explanations, wallpaper selection and hanging advice, exterior painting guides, room-by-room decorating tips, maintenance advice, and seasonal content. The mix is tailored to your services and the search terms your target customers use."}, {"question": "How much time does AI content save a decorating business?", "answer": "The AI replaces what would be two to four hours of writing per week — time most decorators simply do not have. Your involvement is limited to a brief review of generated content, typically ten to fifteen minutes per week, ensuring accuracy and alignment with your preferences before publication."}, {"question": "Can AI write content about specific paint brands I recommend?", "answer": "Yes. The system can reference specific paint brands, product ranges, and specifications you prefer to work with. This reinforces your expertise and helps customers understand the quality of materials you use, differentiating your service from competitors who use cheaper alternatives."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 11. Painters & Decorators × AI Automation
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'painters-and-decorators',
  'ai-automation',
  'AI automation for painters and decorators addresses the specific operational challenges of running a decorating business: managing a pipeline of quotes at various stages, coordinating multi-room projects across overlapping timelines, handling the weather dependencies that affect exterior work, and maintaining customer relationships that generate repeat business over property lifespans. An AI system can analyse incoming enquiries and predict project value from the description, prioritising high-value full-property redecorations for immediate personal response while acknowledging smaller jobs with automated qualification. It can monitor weather conditions and proactively adjust exterior painting schedules, notifying customers before they chase you. It can track completed projects and trigger repainting reminders at intervals matching the expected lifespan of each surface and finish type. For decorators managing a busy workload of overlapping projects, AI automation transforms the administrative overhead from a daily burden into an automated system that runs itself. We build AI automation for decorators that handles the intelligent admin consuming your evenings.',
  'A successful decorating business generates continuous administrative demands: responding to enquiries, following up quotes, scheduling work, updating customers on progress, requesting reviews, and maintaining relationships with past customers. As your workload grows, this admin grows proportionally — but your capacity to handle it does not. AI automation manages the repetitive intelligent tasks that currently consume your non-working hours, enabling business growth without proportional admin burden.',
  'We build AI automations specific to decorating workflows: intelligent enquiry prioritisation by predicted project value, quote lifecycle management with timed follow-ups, weather-aware exterior work scheduling, multi-room project coordination with customer progress updates, and finish-specific repainting reminder triggers.',
  '[{"title": "Quote pipeline chaos with no systematic tracking", "description": "Decorators typically have a dozen or more outstanding quotes at any time, each at a different stage — awaiting site visit, quoted and awaiting response, deposit pending, scheduled. Without systematic tracking and follow-up, quotes slip through the cracks, customers go cold, and revenue is lost to simple administrative oversight."}, {"title": "Exterior projects disrupted by weather with manual rescheduling", "description": "Rain delays on exterior painting projects require individually contacting each affected customer, rescheduling work around subsequent bookings, and managing the cascade effect on upcoming jobs. This reactive coordination consumes hours of communication time that could be systematised and automated."}, {"title": "No system for turning one-room jobs into full-property relationships", "description": "A customer who hires you for a single bedroom is a prime candidate for hallways, bathrooms, and exterior work over the following years. Without automated relationship management — satisfaction checks, seasonal tips, and room refresh reminders — these customers forget your name and search for a new decorator when the next room needs attention."}]',
  '[{"title": "Intelligent quote pipeline management", "description": "AI tracks every quote from initial enquiry through to completion: automated acknowledgements, timed follow-up sequences, deposit reminders, and scheduling confirmations. High-value quotes are flagged for personal attention while standard jobs follow automated workflows. Nothing falls through the cracks regardless of how busy your work schedule becomes."}, {"title": "Weather-aware exterior scheduling and communication", "description": "AI monitors local weather forecasts and cross-references them with your exterior painting schedule. When rain or unsuitable conditions are predicted, affected customers are notified proactively with revised timelines. When conditions clear, rescheduled work is automatically confirmed and your calendar is updated."}, {"title": "Customer lifecycle management with finish-specific reminders", "description": "AI tracks every completed project and triggers repainting reminders based on the surface type and finish applied — exterior masonry after five to seven years, high-traffic hallways after three to four years, kitchen and bathroom spaces after two to three years. Each reminder references the original project details, maintaining a personalised relationship."}]',
  '[{"question": "How does AI manage a decorator''s quote pipeline?", "answer": "The system tracks every enquiry and quote through defined stages: new enquiry, site visit booked, quote sent, follow-up due, accepted, deposit received, scheduled, and completed. Automated actions trigger at each stage transition — follow-up emails, scheduling confirmations, preparation instructions — ensuring consistent communication without manual tracking."}, {"question": "Can AI handle the scheduling complexity of overlapping decorating projects?", "answer": "Yes. The system manages your project calendar, accounting for estimated durations, drying times between coats, multi-room sequencing, and buffer days for preparation. When weather delays shift exterior work, the system identifies scheduling conflicts and proposes adjusted timelines for your approval."}, {"question": "Will AI automation replace my personal customer relationships?", "answer": "No. AI handles the administrative touchpoints — acknowledgements, follow-ups, scheduling, reminders — that currently consume your time but do not require your personal expertise. This frees you to invest more time in the personal interactions that matter: site consultations, colour advice, and the quality conversations that build lasting customer relationships."}, {"question": "What does AI automation cost for a decorating business?", "answer": "AI automation is scaled to your business size and needs. Most decorators start with enquiry management and quote follow-up automation, then expand to weather scheduling and customer lifecycle management as they see results. The investment is typically recovered within the first month through improved quote conversion and recovered follow-up revenue."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;
